// ---- shared helpers --------------------------------------------------------
// keep maxHp sane after a penalty and clamp current hp into the new range.
function epLowerHp(p, amt) {
  p.stats.maxHp = Math.max(20, p.stats.maxHp - amt);
  p.hp = Math.min(p.hp, p.stats.maxHp);
}

