// prism lance bolt — elongated white-hot crystal sliver (points up; engine rotates).
defineSprite('ep_proj_prism', 8, 10, (p) => {
  for (let y = 0; y < 10; y++) {
    const w = y < 2 ? 0.4 : (y < 7 ? 0.6 + (y - 2) * 0.34 : 2.4 - (y - 7) * 0.7);
    p.hline(4 - w, 3 + w, y, y < 4 ? P.shardL : P.shard);
  }
  p.vline(0, 9, 4, P.white);
  p.px(4, 1, P.white);
  p.outline(P.ink);
}, { anchor: [4, 5] });

