// shared: paint a small four-way prismatic glint, for the 稜彩 motif.
function epPrismGlint(p, cx, cy) {
  p.px(cx, cy - 2, P.red); p.px(cx + 1, cy - 1, P.gold);
  p.px(cx + 2, cy, P.green); p.px(cx + 1, cy + 1, P.blueL);
  p.px(cx, cy + 2, P.purpleL); p.px(cx - 1, cy + 1, P.shardL);
  p.px(cx - 2, cy, P.iceD); p.px(cx - 1, cy - 1, P.emberL);
  p.px(cx, cy, P.white);
}

